"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[492],{2934:e=>{e.exports=JSON.parse('{"functions":[{"name":"register","desc":"Registers a gamemode type with a tick function. Must be called before\\n`GamemodeCore.new` for that type. Registering the same type twice\\noverwrites the previous registration with a warning.\\n\\n```lua\\nGamemodeCore.register(\\"MyMode\\", function(self, dt)\\n    if self.Elapsed > 300 then\\n        self:Stop(nil)\\n    end\\nend)\\n```","params":[{"name":"gmType","desc":"Unique identifier for this gamemode type.","lua_type":"string"},{"name":"tickFn","desc":"Called every Heartbeat while active and unpaused.","lua_type":"(self: GamemodeCore, dt: number) -> ()"}],"returns":[],"function_type":"static","source":{"line":612,"path":"modules/gamemode-core/src/init.luau"}},{"name":"new","desc":"Creates a new `GamemodeCore` instance of the given registered type.\\nEvery key in `config` is shallow-copied onto the instance.\\n\\n```lua\\nlocal gm = GamemodeCore.new(\\"MyMode\\", \\"RoundOne\\", {\\n    ScoreLimit = 100,\\n})\\n```","params":[{"name":"gmType","desc":"A type previously registered with `GamemodeCore.register`.","lua_type":"string"},{"name":"name","desc":"Unique name for this instance. Used by `GamemodeCore.getByName`.","lua_type":"string"},{"name":"config","desc":"Key-value pairs copied onto the instance.","lua_type":"Config"}],"returns":[{"desc":"","lua_type":"GamemodeCore"}],"function_type":"static","source":{"line":637,"path":"modules/gamemode-core/src/init.luau"}},{"name":"getByName","desc":"Returns the `GamemodeCore` instance registered under `name`, or `nil`\\nif no such instance exists.","params":[{"name":"name","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"GamemodeCore?"}],"function_type":"static","source":{"line":704,"path":"modules/gamemode-core/src/init.luau"}},{"name":"mount","desc":"Attaches a reactive function to the gamemode. The function receives the\\ninstance and a `HookContext` and is called every Heartbeat while the\\ngamemode is active and unpaused.\\n\\nReturns an unmount function. Call it to detach the mount and run any\\npending `useEffect` cleanups.\\n\\n```lua\\nlocal unmount = gm:mount(function(self, ctx)\\n    local score, setScore = ctx:useState(0)\\n\\n    ctx:useEffect(function()\\n        local c = self.Stopped:Connect(function() setScore(0) end)\\n        return function() c:Disconnect() end\\n    end, {})\\nend)\\n\\n-- later:\\nunmount()\\n```","params":[{"name":"fn","desc":"Reactive function to mount.","lua_type":"(gm: GamemodeCore, ctx: HookContext) -> ()"}],"returns":[{"desc":"Call to unmount and clean up.","lua_type":"() -> ()"}],"function_type":"method","source":{"line":734,"path":"modules/gamemode-core/src/init.luau"}},{"name":"Start","desc":"Starts the gamemode. Transitions `Active` to `true`, resets `Elapsed`\\nto `0`, begins the Heartbeat loop, ticks all mounted functions once,\\nthen fires `Started`.\\n\\nDoes nothing if already active.","params":[{"name":"metadata","desc":"Optional value forwarded to `Started` listeners.","lua_type":"any?"}],"returns":[],"function_type":"method","source":{"line":766,"path":"modules/gamemode-core/src/init.luau"}},{"name":"Stop","desc":"Stops the gamemode. Disconnects the Heartbeat loop, flushes all\\n`useEffect` cleanups, fires `Stopped`, then resets `Elapsed` to `0`.\\n\\nDoes nothing if not active.","params":[{"name":"winner","desc":"Passed as the first argument to `Stopped` listeners.","lua_type":"any?"},{"name":"metadata","desc":"Passed as the second argument to `Stopped` listeners.","lua_type":"any?"}],"returns":[],"function_type":"method","source":{"line":809,"path":"modules/gamemode-core/src/init.luau"}},{"name":"Pause","desc":"Pauses the gamemode, suspending the tick loop and mount calls.\\nFires `OnPaused`. Does nothing if not active or already paused.","params":[{"name":"metadata","desc":"Optional value forwarded to `OnPaused` listeners.","lua_type":"any?"}],"returns":[],"function_type":"method","source":{"line":838,"path":"modules/gamemode-core/src/init.luau"}},{"name":"Resume","desc":"Resumes a paused gamemode. Does nothing if not active or not paused.","params":[],"returns":[],"function_type":"method","source":{"line":851,"path":"modules/gamemode-core/src/init.luau"}},{"name":"Destroy","desc":"Destroys the gamemode. Fires `Destroying`, stops the round if active,\\ndestroys all mounts and signals, and removes the instance from the\\nglobal registry.\\n\\nAfter calling this, the instance must not be used again.","params":[],"returns":[],"function_type":"method","source":{"line":867,"path":"modules/gamemode-core/src/init.luau"}}],"properties":[{"name":"Started","desc":"Fires when the gamemode starts. Receives the optional metadata passed to `Start`.\\n\\t","lua_type":"Signal<any?>","source":{"line":662,"path":"modules/gamemode-core/src/init.luau"}},{"name":"Stopped","desc":"Fires when the gamemode stops. Receives the winner and optional metadata passed to `Stop`.\\n\\t","lua_type":"Signal<any?, any?>","source":{"line":669,"path":"modules/gamemode-core/src/init.luau"}},{"name":"OnPaused","desc":"Fires when the gamemode is paused. Receives the optional metadata passed to `Pause`.\\n\\t","lua_type":"Signal<any?>","source":{"line":676,"path":"modules/gamemode-core/src/init.luau"}},{"name":"ElapsedChanged","desc":"Fires every Heartbeat while the gamemode is active and unpaused, with the current elapsed time.\\n\\t","lua_type":"Signal<number>","source":{"line":683,"path":"modules/gamemode-core/src/init.luau"}},{"name":"Destroying","desc":"Fires just before the gamemode is destroyed.\\n\\t","lua_type":"Signal<GamemodeCore>","source":{"line":690,"path":"modules/gamemode-core/src/init.luau"}}],"types":[{"name":"Config","desc":"A free-form config table passed to `GamemodeCore.new`. Every key is\\ncopied directly onto the instance.","lua_type":"{ [string]: any }","source":{"line":561,"path":"modules/gamemode-core/src/init.luau"}}],"name":"GamemodeCore","desc":"Reactive hook-based gamemode lifecycle core.\\n\\nRegister a gamemode type with `GamemodeCore.register`, then create\\ninstances with `GamemodeCore.new`. Each instance manages an Active/Paused\\nstate machine, a per-frame tick loop, and a React-style hook system via\\n`mount`.\\n\\n```lua\\nlocal GamemodeCore = require(Packages.GamemodeCore)\\n\\nGamemodeCore.register(\\"MyMode\\", function(self, dt)\\n    -- custom per-frame logic\\nend)\\n\\nlocal gm = GamemodeCore.new(\\"MyMode\\", \\"RoundOne\\", {\\n    ScoreLimit = 100,\\n})\\n\\ngm.Stopped:Connect(function(winner, metadata)\\n    print(\\"Winner:\\", winner)\\nend)\\n\\ngm:Start()\\n```","source":{"line":553,"path":"modules/gamemode-core/src/init.luau"}}')}}]);